sql:
SELECT COUNT(DISTINCT patient_id)
FROM health_records
WHERE record_type = 'postnatal visit';

SELECT COUNT(patient_id)
FROM patients
WHERE annual_household_income > (SELECT AVG(annual_household_income) FROM patients);

SELECT p.patient_name, b.apgar_score_10min as highest_apgar_score_10min
FROM patients p
JOIN births b ON p.patient_id = b.pregnancy_id
WHERE b.apgar_score_10min = (
    SELECT MAX(apgar_score_10min) FROM births
);

SELECT birth_weight, apgar_score_10min, head_circumference
FROM births
WHERE delivery_method = 'vaginal' AND apgar_score_10min > 9;

external_knowledge:
- "stars in the obstetric firmament" metaphorically refers to patients visiting obstetric clinics;
- "annual household incomes below the modest five-figure mark" refers to an annual household income less than $50,000;
- "embarked on the prenatal journey" indicates patients who have had prenatal visits;
- "coordinates in the digital cosmos" metaphorically means contact phone numbers;
- "newborns' overall vitality scores at the dawn of life" indicates the average Apgar score at 1, 5, and 10 minutes after birth.

